record.field:
# Monitor SLA for active tasks
active_tasks = env['bmp.task.instance'].search([
    ('status', 'in', ['ready', 'claimed', 'in_progress']),
    ('due_date', '!=', False)
])

for task in active_tasks:
    sla_rules = env['bmp.sla.rule'].get_applicable_rules(task)
    for rule in sla_rules:
        if rule.check_sla_warning(task):
            # Send warning notification
            pass
        if rule.check_sla_breach(task):
            rule.escalate_task(task)
            break
